select a.write_year ,a.doc_type ,a.doc_no ,a.comp_id ,a.legal_review_nm ,a.use_yn ,a.created_at , count(b.doc_seq) as cnt, 'U' as cmd, esg.fn_getapprovalstatus('LGR', a.write_year || a.doc_no) as approval_status from esg.tb_legal_review a left join esg.tb_legal_review_detail b on a.write_year = b.write_year and a.doc_type = b.doc_type and a.doc_no = b.doc_no and b.use_yn = 'Y' where A.comp_id = #{compId}
and A.doc_type = #{docType}
and A.doc_no = #{docNo}
group by a.write_year ,a.doc_type ,a.doc_no ,a.comp_id ,a.use_yn ,a.created_at order by A.write_year DESC, A.use_yn DESC, a.created_at desc

select A.write_year , A.doc_no , A.doc_type , A.comp_id , A.legal_review_nm , A.use_yn , created_at , created_by , updated_at , updated_by , 'U' as cmd from esg.tb_legal_review A where A.write_year = #{writeYear} and A.comp_id = #{compId}
and A.doc_no = #{docNo}
and A.doc_type = #{docType}
ORDER BY A.use_yn DESC, A.created_at desc

select A.write_year , A.doc_type , A.doc_no , A.doc_seq , coalesce(A.legal_write_year,'') as legal_write_year , coalesce(A.legal_doc_type,'') as legal_doc_type , coalesce(A.legal_doc_no,'') as legal_doc_no , coalesce(A.legal_doc_seq ,'') as legal_doc_seq , coalesce(D.legal_nm ,'') as legal_nm , coalesce(C.article_title,'') as legal_article_nm , A.revision_at , coalesce(A.currentlaws,'') as currentlaws , coalesce(A.facility,'') as facility , coalesce(A.remark_dc,'') as remark_dc , A.use_yn , A.created_at , A.created_by , A.updated_at , A.updated_by , 'U' as cmd , B.legal_review_nm from esg.tb_legal_review_detail A left join esg.tb_legal_review B on a.write_year = b.write_year and a.doc_type = b.doc_type and a.doc_no = b.doc_no and b.comp_id = #{compId} left join esg.tb_legal_manage_detail C on a.legal_write_year = c.write_year and a.legal_doc_type =c.doc_type and a.legal_doc_no = c.doc_no and a.legal_doc_seq = c.doc_seq left join esg.tb_legal_manage D on c.write_year =d.write_year and c.doc_type = d.doc_type and c.doc_no = d.doc_no
where A.write_year = #{writeYear} and D.comp_Id = #{compId}
and A.doc_no = #{docNo}
and A.doc_type = #{docType}
ORDER BY A.use_yn DESC, CAST(a.doc_seq AS INTEGER) desc

SELECT tlrdo.write_year , tlrdo.doc_type , tlrdo.doc_no , tlrdo.doc_seq , tlrdo.orgn_id , tlrdo.orgn_nm FROM esg.tb_legal_review_detail_orgn tlrdo LEFT JOIN esg.tb_legal_review_detail tlrd ON tlrd.write_year = tlrdo.write_year and tlrd.doc_type = tlrdo.doc_type and tlrd.doc_no = tlrdo.doc_no and tlrd.doc_seq = tlrdo.doc_seq WHERE tlrdo.write_year = #{writeYear}
AND tlrdo.doc_no = #{docNo}
AND tlrdo.doc_type = #{docType}
AND tlrdo.doc_seq = #{docSeq}
ORDER BY CAST(tlrdo.doc_seq AS INTEGER) DESC, tlrdo.orgn_id ASC

        SELECT
			LPAD((COALESCE(MAX(doc_no::INTEGER), 0) + 1)::TEXT, 5, '0') AS docNo
	    FROM esg.tb_legal_review
		WHERE write_year = #{writeYear}
			AND doc_type = #{docType}

