select  a.write_year,
		a.doc_type ,
		a.doc_no ,
	    a.created_at ,
		a.created_by ,
		a.updated_at ,
		a.updated_by 
	from esg.tb_legal_review a
	where a.comp_id = #{compId}
    and   a.write_year = #{writeYear}
    and   a.doc_type = #{docType}
    and   a.doc_no = #{docNo}

WITH original_data AS ( SELECT c.article_title as legalArticleNm , b.revision_at , b.currentlaws , b.facility , b.remark_dc , b.doc_no , row_number() OVER (ORDER BY b.doc_no, b.doc_seq DESC)::text AS doc_seq , STRING_AGG(d.orgn_nm, E'\n' ORDER BY d.orgn_id) AS orgn_nm , e.legal_nm FROM esg.tb_legal_review a LEFT JOIN esg.tb_legal_review_detail b ON a.write_year = b.write_year AND a.doc_type = b.doc_type AND a.doc_no = b.doc_no LEFT JOIN esg.tb_legal_manage_detail c ON b.legal_write_year = c.write_year AND b.legal_doc_type = c.doc_type AND b.legal_doc_no = c.doc_no AND b.legal_doc_seq = c.doc_seq LEFT JOIN esg.tb_legal_review_detail_orgn D on a.doc_no = d.doc_no and b.doc_seq = d.doc_seq LEFT JOIN esg.tb_legal_manage E on e.doc_no = c.doc_no and e.comp_id = a.comp_id WHERE a.comp_id = #{compId} AND a.write_year = #{writeYear} AND a.doc_type = #{docType} AND a.doc_no = #{docNo} AND b.doc_seq IN
#{gridValue}
GROUP BY c.article_title, b.revision_at, b.currentlaws, b.facility, b.remark_dc, b.doc_no, b.doc_seq, e.legal_nm
AND b.use_yn = 'Y'
),
data_count AS ( SELECT COUNT(*) AS row_count FROM original_data )
SELECT * FROM original_data UNION ALL SELECT '' AS article_title, '' AS revision_at, '' AS currentLaws, '' AS facility, '' AS remark_dc, '' AS doc_no, '' AS doc_seq, '' AS orgn_nm, '' as legal_nm FROM generate_series(1, 0 - ((SELECT row_count FROM data_count)%20)) WHERE ((SELECT row_count FROM data_count)%20) < 20 order by doc_no, doc_seq ASC;

    select t1.*
	from esg.tb_legal_review t1
	where t1.write_year = #{writeYear}
		and t1.comp_id = #{compId}
		and t1.use_yn = 'Y'
	order by t1.doc_no asc
